const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const seenPath = path.join(vaultPath, 'JobFilter', 'Agent Runs', '.seen-lead-ids.json');
const input = $input.first().json;
const incoming = Array.isArray(input.leads) ? input.leads : [];
const agent = input.agent || 'unknown';
let seen = {};
if (fs.existsSync(seenPath)) { try { seen = JSON.parse(fs.readFileSync(seenPath, 'utf-8')); } catch {} }
seen.ids = seen.ids || {};
const now = Date.now();
const expiryMs = 14 * 86400000;
for (const id of Object.keys(seen.ids)) { if (now - seen.ids[id] > expiryMs) delete seen.ids[id]; }
const fresh = [];
const dupes = [];
for (const lead of incoming) {
  const id = lead.id || lead.leadId || `${lead.source}-${lead.title}`;
  if (!id) { fresh.push(lead); continue; }
  if (seen.ids[id]) { dupes.push(id); continue; }
  seen.ids[id] = now;
  fresh.push(lead);
}
fs.mkdirSync(path.dirname(seenPath), { recursive: true });
fs.writeFileSync(seenPath, JSON.stringify(seen, null, 2));
return [{ json: { fresh, freshCount: fresh.length, dupeCount: dupes.length, dupeIds: dupes, agent } }];
